def admin_panel():
    is_admin_param = request.args.get('is_admin')

    if not is_admin_param:
        return "Missing required parameter 'is_admin'.", 400

    if is_admin_param.lower() == 'true':
        return "Welcome to the Admin Panel!"
    else:
        abort(403)  # Forbidden

